var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"태스크포스 <color=#ffd34c>그릴 파티</color>\\n<color=#ffd34c>카나리아 스쿼드</color> 모의 훈련 중","JPN":"タスクフォース<color=#ffd34c>グリルパーティー</color>\\n<color=#ffd34c>カナリア・スクワッド</color>の模擬訓練中","ENG":"TASKFORCE <color=#ffd34c>Grill Party</color>\\n<color=#ffd34c>Canary Squad</color> in mock battle","TWN":"特遣勢力<color=#ffd34c>格里爾派提</color>\\n<color=#ffd34c>金絲雀小隊</color>模擬訓練中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"누가 이 시간까지 훈련하나 했더니. 또 너희들이네.","JPN":"誰がこんな時間まで訓練してるのかって思ったら。またあなたたちなの。","ENG":"I was wondering who was training this late. It's you again.","TWN":"我還想說是誰在這個時間訓練，結果又是你們。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"안녕하세요, 관리부장.","JPN":"こんばんは、管理部長。","ENG":"Hello.","TWN":"管理部長好。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미안. 이 꼬맹이가 훈련이 부족하다고 들들 볶아서.","JPN":"悪い。このおこちゃまが訓練不足だってしつこくてさ。","ENG":"Sorry. She's been whining about how we don't train enough.","TWN":"抱歉，因為這小鬼一直吵說訓練不夠。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"싸울 때 라이카가 조건반사적으로 움직이게 만드는 게 제 목표예요.","JPN":"戦うときに、ライカが条件反射的に動くようにするのが私の目標なんです。","ENG":"It's my goal to improve Laika's combat reflexes to the limit.","TWN":"我的目標是讓萊卡在作戰時建立制約反射。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다른 소대랑 대항 훈련 할 때도 맨날 딴청 피우다 당하거든요.","JPN":"他の小隊と対抗訓練する時にも、いつもとぼけててやられてしまって。","ENG":"During battle practice with other squads, they always get the best of her while she's distracted.","TWN":"和其他小隊練習對打時，每次都因為不專心而挨打。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어른답지 못해요. 아니, 개만도 못해.","JPN":"大人らしくありません。いえ、犬以下です。","ENG":"It's not very adult-like. Even dogs would do better than you.","TWN":"一點也不像個大人，不，是連狗都不如。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 너 다른 사람한테 그딴 식으로 말하면 총 맞아. 나니까 참아 주지.","JPN":"おい、他のやつにそんなこと言ったら撃たれるぞ。私だから我慢してやれるんだ。","ENG":"Hey, you know people would normally shoot you for saying that? I'm the only one kind enough to tolerate it.","TWN":"喂，這些話你要是跟別人說，是會被槍殺的。因為是我，才能忍受你好嗎？"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"객관적인 평가네요. 흥.","JPN":"客観的な評価だこと。ふん。","ENG":"I guess that's an objective assessment. Hmph.","TWN":"我只是實話實說，哼。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"펠리세트 말도 일리는 있어. 라이카 넌 진지할 때가 없으니까.","JPN":"フェリセットの言葉も一理ある。ライカはいつも真面目にやらないからね。","ENG":"Félicette has a point, Laika. You don't take things very seriously.","TWN":"費莉塞特說的也不無道理，萊卡你確實很容易分心。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"곧 건틀렛 데뷔지? 좋은 성적 거둬서 제대로 된 스폰서 하나 물어 와.","JPN":"もうすぐガントレットのデビュー戦でしょう？　いい成績取って、ちゃんとしたスポンサーを捕まえてきなさい。","ENG":"Aren't you making your debut at the Gauntlet League soon? Do your best, and hopefully you'll get a decent sponsor.","TWN":"馬上就要參加聖鎧了吧？拿個好成績，拉個像樣的贊助回來。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"너희들 장비에 붙여 놓은 스폰서 로고도 다 선배들이 건져 온 거니까.","JPN":"あなたたちの装備に貼ってあるスポンサーのロゴも、全部先輩たちが取ってきたんだから。","ENG":"Those sponsor logos on your gear are the work of your seniors, after all.","TWN":"你們裝備上貼的贊助商標誌也都是前輩們贏回來的。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"걱정 마세요. 본선 결승이 제 목표니까요.","JPN":"心配しないでください。私が狙ってるのは、本戦決勝ですから。","ENG":"Don't worry. I'm aiming for the finals.","TWN":"不用擔心，我的目標是打入決賽。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"참 징그럽게 호들갑이야, 얘. 비싼 로고엔 침식체 이빨이라도 안 박히나.","JPN":"まったく、大げさだな。お高いロゴには侵食体の歯を防ぐ効果でもあるのか？","ENG":"So dramatic. It's not like the logos are C.O.-proof.","TWN":"真是矯情，有贊助商的標誌，就不會被侵蝕體的牙齒咬破嗎？"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"그 대신에 돈과 명예가 생기잖아.","JPN":"それはないけど、お金と名誉が与えられるじゃない。","ENG":"But it'll bring you wealth and fame.","TWN":"那倒不是，但是可以獲得金錢和榮譽。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"기사 못 봤어? 요즘 초등학생들 장래희망 1순위가 건틀렛 챔피언이야.","JPN":"ニュース見てないの？　今時の小学生の将来の夢で1位がガントレットのチャンピオンなのよ。","ENG":"Didn't you read those new articles? The top voted dream among elementary school students is becoming a Gauntlet champion.","TWN":"你沒看新聞嗎？最近連小學生的第一志願都是聖鎧冠軍。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"와, 요즘 애들 되게 살 만한가 보다. 나 때는 빠른 자살이었는데.","JPN":"うわ、最近の子どもって贅沢だな。私の時にはさくっと自殺することだったのに。","ENG":"Damn, they must have it good. Back in my day, the top voted option was \\"quick death.\\"","TWN":"哇，看來最近的孩子過得蠻爽的嘛。我那時候是比誰先自殺。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"휴식 시간 10분 초과.","JPN":"休憩時間、10分超過。","ENG":"We exceeded our 10-minute break time.","TWN":"休息時間超過10分鐘了。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"장비 챙겨서 일어나요, 라이카. 돌입할 때 격발 시간을 더 단축시켜야 하니까.","JPN":"装備を持って立って、ライカ。突入するときの撃発時間をもっと短縮させないと。","ENG":"Get your stuff and stand up, Laika. We need to cut your fire time after charging in.","TWN":"拿起你的裝備來，萊卡。突擊時的射擊時間還要再縮短一點。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러지 말고 오늘은 그냥 쉬자. 하루 종일 했잖아.","JPN":"これくらいにして、今日はもう休もう。一日中ずっとやってるだろ？","ENG":"Can't we just take the rest of the day off? We've been at it all day long.","TWN":"不要啦，今天就到此為止吧？我們都訓練一整天咧？"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"전 아직 더 할 수 있어요.","JPN":"私はまだ行けるわ。","ENG":"I can practice more.","TWN":"我還能繼續。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"땀으로 샤워한 꼴로 무슨….","JPN":"汗だくのくせに……","ENG":"You're drenched in sweat.","TWN":"你都渾身是汗咧……"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"그러지 말고 데뷔전까지만 집중해. 다들 본선 진출을 노리고 있으니까.","JPN":"そんなこと言ってないで、デビュー戦までは集中するのよ。みんな本戦進出を狙ってるんだから。","ENG":"Just try to focus on the debut game. Everyone's trying to get through the qualifiers.","TWN":"比賽前就先專心訓練吧。大家都想打入決賽呢。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어휴, 그러시겠죠.","JPN":"はあ、へいへい。","ENG":"Ugh, of course they are.","TWN":"呼，好吧好吧。"},"stage":{"bg":"TRAINING","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……응? 경보음?","JPN":"……む？　警報音？","ENG":"...Hmm? Is that the alarm bell?","TWN":"……嗯？警報聲？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"새삼스러울 거 없잖아요. 관할 구역에 침식체라도 나타났나 보죠.","JPN":"何を今更。管轄区域に侵食体でも現れたんでしょ。","ENG":"It's hardly a big deal. There's probably a C.O. in our area of jurisdiction.","TWN":"有什麼好大驚小怪的？應該是我們的轄區又出現侵蝕體了吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"근무 중인 소대가 나서면 될 일이에요. 딴청 피우지 말고 훈련에 집중해요.","JPN":"勤務中の小隊が向かえばいいのよ。とぼけてないで訓練に集中して。","ENG":"There should be a squad on duty that can handle it. Just focus on training.","TWN":"交給執勤中的小隊去處理就好。你別管這麼多，快點訓練。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"넌 어떻게 된 애가 입만 열면 훈련이냐? 아주 결혼도 훈련 받고 해라.","JPN":"あんたはいっつも訓練、訓練って。結婚も訓練してしたら？","ENG":"How are you so obsessed with training? You wanna get training before you get married too?","TWN":"你到底怎麼回事？怎麼開口閉口都是訓練？乾脆結婚你也等訓練完再結吧！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"쉿. 다들 조용히.","JPN":"しっ。みんな、静かに。","ENG":"Shhh. Quiet, everyone.","TWN":"噓，你們二個都閉嘴。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"이거…. 우리 건물 방송이 아니야.","JPN":"これ……この建物のアナウンスじゃない。","ENG":"This... isn't coming from our building.","TWN":"這……不是我們大樓的廣播。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>샤레이드 도시 관리국에서 알려드립니다.</color>","JPN":"<color=#ffd34c>シャレード都市管理局からお知らせいたします。</color>","ENG":"<color=#ffd34c>Attention. This is Charade's City Management.</color>","TWN":"<color=#ffd34c>來自查雷德城市管理局的通知。</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현 시간 부로 소집 명령이 하달되었습니다. 전 태스크포스는 모든 가용 인원을 관할 구역에 배치해 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>現時刻をもって、招集命令が発令されました。全タスクフォースは、すべての可動人員を管轄区域に配置してください。</color>","ENG":"<color=#ffd34c>A call up order has been issued as of this time. All TASKFORCEs must deploy all able members to the appropriate area of jurisdiction.</color>","TWN":"<color=#ffd34c>現在發佈召集令，請所有特遣勢力將可動員人力佈署至轄區。</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다시 한 번 안내드리겠습니다. 현 시간 부로 소집 명령이 하달되었습니다. 전 태스크포스는…</color>","JPN":"<color=#ffd34c>再度お知らせいたします。現時刻をもって、招集命令が発令されました。全タスクフォースは……</color>","ENG":"<color=#ffd34c>Once again, a call-up order has been issued as of this time. All TASKFORCEs must deploy all able–</color>","TWN":"<color=#ffd34c>再重複一遍。現在發佈召集令，請所有特遣勢力……</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"들었지? 둘 다 얼른 장비 챙겨!","JPN":"聞いた？　二人とも、早く装備を持って！","ENG":"Heard that? Get your gear, now!","TWN":"聽到沒？趕快帶著你們的裝備！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"건틀렛은요? 훈련에 집중하라고 했잖아요?","JPN":"ガントレットはどうするんですか？　訓練に集中しろって言ったじゃないですか。","ENG":"What about the Gauntlet League? I thought you wanted us to focus on training!","TWN":"那聖鎧怎麼辦？你不是叫我們專心訓練嗎？"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"관리국이 소집할 정도면 보통 대형 이벤트가 아니야.","JPN":"管理局が召集するくらいなら、ただのイベントじゃないはずよ。","ENG":"If City Management's issuing the order, something serious is about to happen.","TWN":"管理局都發佈召集令了，肯定不是一般的行動。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"이럴 때 기회를 잡으면 스폰서들 눈에 드는 건 식은 죽 먹기라고! 자, 얼른!","JPN":"こういう時にチャンスをモノにすれば、スポンサーの目に留まるのなんて朝飯前よ。ほら、早く！","ENG":"It's a great chance to stand out and leave a good impression on potential sponsors! Go, now!","TWN":"當然要把握住這個能夠被贊助商看見的機會！動作快！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"치. 어른들은 전부 이랬다 저랬다 해.","JPN":"ちっ。大人はみんなすぐ態度を変えるんだから。","ENG":"Tch. Adults always change their mind.","TWN":"哼，大人翻臉比翻書還快。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"인상 좀 펴라. 침식체든 뭐든 잡는 게 훈련보단 덜 따분해.","JPN":"そんな顔するなよ。侵食体でもなんでもやっつけてる方が、訓練よりはましだよ。","ENG":"Turn that frown upside down, will you? C.O. hunting's gonna be more entertaining than training.","TWN":"別這麼一臉不情願嘛，對付侵蝕體比訓練好玩吧？"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"슬슬 실전 경험할 때도 됐잖아? 같은 팀 사람들이랑 모의전 벌이는 것도 한계가 있다고.","JPN":"そろそろ実戦を経験してもいい時期だろ？　同じチームの人たちと模擬戦するのにも限界があるしさ。","ENG":"It's time you get some field experience anyway. There's a limit to challenging other teammates to mock battles, you know.","TWN":"而且現在也該進入實戰體驗了吧？老是和同一隊的人進行模擬戰，進步的空間也很有限。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그건……. 그렇긴 해요. 실전에 참가할 기회는 드물긴 하죠.","JPN":"それは……確かにそうだけど。実戦に参加するチャンスは滅多にないもの。","ENG":"I guess... that's true. It's not often you get to go out on the field.","TWN":"這個嘛……你說的是沒錯，可以參與實戰的機會確實不多。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"알겠어요. 그럼 이번에 연습한 대형을 시험해 볼래요.","JPN":"わかったわ。じゃあ、今回練習した隊形を試してみることにする。","ENG":"Fine. Then I'd like to test out the new formation we've been practicing.","TWN":"好吧，那我要試試這次練習的隊形。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래라, 그래….","JPN":"はい、はい……","ENG":"Sure, whatever you want...","TWN":"好啊，你開心就好……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하여튼 건틀렛에 환장했다니까. 누가 꼬맹이 아니랄까 봐.","JPN":"まったく、ガントレットのことばっかりなんだから。さすがおこちゃま。","ENG":"She's so obsessed with the Gauntlet. Guess she really is a child.","TWN":"你想什麼我還不知道嗎？腦袋裡就只想著聖鎧……"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"악!","JPN":"いたっ！","ENG":"Argh!","TWN":"啊！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭐 해요, 멍하니 서서? 그만 중얼거리고 따라와요.","JPN":"何してるの、ボーっとして。ぶつぶつ言ってないでついて来て。","ENG":"What are you doing, standing around? Stop mumbling and follow me.","TWN":"發什麼呆？在那邊嘀咕什麼，趕快跟上。"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 이 사이코 꼬맹아! 내가 헬멧 던지지 말랬지!","JPN":"おい、このサイコガキ！　ヘルメット投げんなっつっただろ！","ENG":"Hey, psycho kid! I told you not to throw your helmet at me!","TWN":"喂，你這個小瘋子！我說過不要用頭盔砸我！"},"stage":{"bg":"TRAINING","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};